## 2. The C / C++ glue – `pcapng_stubs.c`

> **Important** – this file must be compiled **as C++** (e.g. `g++ -c -std=c++17 …`) because it
> includes the C++ header from `libpcapng`.  The file is named *.c* only to keep the
> OCaml build system happy; the `extern "C"` block guarantees a C ABI.

```c
/*--------------------------------------------------------------------
   pcapng_stubs.c – C/C++ glue for the OCaml libpcapng bindings
   --------------------------------------------------------------------*/

#define CAML_NAME_SPACE
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/custom.h>
#include <caml/fail.h>
#include <caml/callback.h>
#include <caml/bigarray.h>

#include <stdexcept>
#include <string>
#include <memory>

/* ------------------------------------------------------------------
   The (hypothetical) libpcapng C++ API.
   ------------------------------------------------------------------ */
extern "C" {
    // In reality you would #include <pcapng.hpp> or similar.
}
#include "libpcapng.hpp"      // <-- replace with the real header

/* ------------------------------------------------------------------
   OCaml view of a pcapng file (the opaque type `t`).
   ------------------------------------------------------------------ */
typedef std::shared_ptr<pcapng::Reader> pcapng_reader_ptr;

/* Finaliser: called when the OCaml value is GC‑collected */
static void pcapng_finalize(value v)
{
    pcapng_reader_ptr *p = (pcapng_reader_ptr *)Data_custom_val(v);
    delete p;                 // shared_ptr destructor releases the Reader
}

/* Comparison – not needed, but OCaml requires a stub */
static int pcapng_compare(value v1, value v2)
{
    pcapng_reader_ptr *p1 = (pcapng_reader_ptr *)Data_custom_val(v1);
    pcapng_reader_ptr *p2 = (pcapng_reader_ptr *)Data_custom_val(v2);
    return (*p1 < *p2) ? -1 : (*p1 > *p2) ? 1 : 0;
}

/* Hash – again, just a stub */
static long pcapng_hash(value v)
{
    pcapng_reader_ptr *p = (pcapng_reader_ptr *)Data_custom_val(v);
    return (long)(*p).get();
}

/* Custom operations table */
static struct custom_operations pcapng_custom_ops = {
    "pcapng.reader",
    pcapng_finalize,
    pcapng_compare,
    pcapng_hash,
    custom_serialize_default,
    custom_deserialize_default,
    custom_compare_ext_default,
    custom_fixed_length_default
};

/* ------------------------------------------------------------------
   Helper: raise the OCaml exception Pcapng.Error with a string
   ------------------------------------------------------------------ */
static void raise_error(const std::string &msg)
{
    static value *exn = NULL;
    if (exn == NULL) {
        exn = caml_named_value("Pcapng.Error");
        if (exn == NULL) caml_failwith("Pcapng.Error not registered");
    }
    caml_raise_with_string(*exn, msg.c_str());
}

/* ------------------------------------------------------------------
   OCaml primitives
   ------------------------------------------------------------------ */

/* val open_file : string -> t */
CAMLprim value caml_pcapng_open_file(value v_path)
{
    CAMLparam1(v_path);
    CAMLlocal1(v_res);

    const char *c_path = String_val(v_path);
    try {
        // Construct the C++ Reader object (throws on error)
        std::shared_ptr<pcapng::Reader> *ptr =
            new std::shared_ptr<pcapng::Reader>(new pcapng::Reader(c_path));

        // Allocate OCaml custom block and store the pointer
        v_res = caml_alloc_custom(&pcapng_custom_ops,
                                  sizeof(pcapng_reader_ptr), 0, 1);
        pcapng_reader_ptr *dst = (pcapng_reader_ptr *)Data_custom_val(v_res);
        *dst = *ptr;          // copy the shared_ptr (reference counted)
        delete ptr;           // the temporary we just allocated
    } catch (const std::exception &e) {
        raise_error(e.what());
    }

    CAMLreturn(v_res);
}

/* ------------------------------------------------------------------
   Convert a native pcapng::Frame into an OCaml `frame` record.
   The OCaml record layout must match the one declared in pcapng.mli.
   ------------------------------------------------------------------ */
static value caml_frame_of_native(const pcapng::Frame &frm)
{
    CAMLparam0();
    CAMLlocal3(v_rec, v_ts, v_data);

    // 1. Timestamp (seconds + microseconds)
    v_ts = caml_alloc_tuple(2);
    Store_field(v_ts, 0, Val_int(frm.timestamp_sec));
    Store_field(v_ts, 1, Val_int(frm.timestamp_usec));

    // 2. Payload – copy into a fresh Bytes.t
    v_data = caml_alloc_string(frm.caplen);
    memcpy(String_val(v_data), frm.payload.data(), frm.caplen);

    // 3. Assemble the record (order must match .mli)
    v_rec = caml_alloc(5, 0);               // 5 fields, tag 0 (only one constructor)
    Store_field(v_rec, 0, Val_int(frm.timestamp_sec));
    Store_field(v_rec, 1, Val_int(frm.timestamp_usec));
    Store_field(v_rec, 2, Val_int(frm.caplen));
    Store_field(v_rec, 3, Val_int(frm.origlen));
    Store_field(v_rec, 4, v_data);

    CAMLreturn(v_rec);
}

/* ------------------------------------------------------------------
   val next : t -> frame option
   ------------------------------------------------------------------ */
CAMLprim value caml_pcapng_next(value v_reader)
{
    CAMLparam1(v_reader);
    CAMLlocal1(v_opt);

    pcapng_reader_ptr *reader = (pcapng_reader_ptr *)Data_custom_val(v_reader);
    try {
        std::optional<pcapng::Frame> maybe = (*reader)->next_frame();
        if (!maybe) {
            // None
            v_opt = Val_int(0);   // 0 = None for option type
        } else {
            // Some <frame>
            value v_frame = caml_frame_of_native(*maybe);
            v_opt = caml_alloc(1, 0);   // Some
            Store_field(v_opt, 0, v_frame);
        }
    } catch (const std::exception &e) {
        raise_error(e.what());
    }

    CAMLreturn(v_opt);
}

/* ------------------------------------------------------------------
   val iter : t -> (frame -> unit) -> unit
   ------------------------------------------------------------------ */
CAMLprim value caml_pcapng_iter(value v_reader, value v_cb)
{
    CAMLparam2(v_reader, v_cb);
    caml_register_global_root(&v_cb);   // keep the callback reachable

    pcapng_reader_ptr *reader = (pcapng_reader_ptr *)Data_custom_val(v_reader);
    try {
        while (true) {
            std::optional<pcapng::Frame> maybe = (*reader)->next_frame();
            if (!maybe) break;                     // EOF

            value v_frame = caml_frame_of_native(*maybe);
            // Call the OCaml callback.  caml_callback_exn returns an
            // OCaml value; we ignore it (unit) but must check for
            // exceptions.
            value v_res = caml_callback_exn(v_cb, v_frame);
            if (Is_exception_result(v_res)) {
                // Propagate the OCaml exception back to the caller.
                caml_raise(v_res);
            }
        }
    } catch (const std::exception &e) {
        caml_remove_global_root(&v_cb);
        raise_error(e.what());
    }

    caml_remove_global_root(&v_cb);
    CAMLreturn(Val_unit);
}

/* ------------------------------------------------------------------
   Helper for the convenience function `count_frames`.
   It is exposed as a plain C function, not an OCaml primitive.
   ------------------------------------------------------------------ */
extern "C" int pcapng_count_frames(const char *path)
{
    // Simple wrapper that re‑uses the iterator logic.
    std::shared_ptr<pcapng::Reader> r(new pcapng::Reader(path));
    int cnt = 0;
    while (r->next_frame()) ++cnt;
    return cnt;
}

/* ------------------------------------------------------------------
   Register the OCaml exception name – done in the C init function.
   ------------------------------------------------------------------ */
CAMLprim value caml_pcapng_init(value unit)
{
    CAMLparam1(unit);
    // Register the exception so that `raise_error` can find it.
    caml_register_named_value("Pcapng.Error", caml_named_value("Pcapng.Error"));
    CAMLreturn(Val_unit);
}
```

### 2.1. What the stub does

| OCaml primitive | What the stub does |
|-----------------|--------------------|
| `open_file` | Constructs a `std::shared_ptr<pcapng::Reader>` (the C++ iterator) and stores it inside an OCaml *custom block*. The block is finalised automatically (`pcapng_finalize`). |
| `next` | Calls `Reader::next_frame()` once, converts the returned C++ `Frame` into an OCaml `frame` record, and returns `Some frame` or `None`. |
| `iter` | Loops over the iterator, converting each native frame to an OCaml value and invoking the user‑supplied callback (`v_cb`). If the callback raises, the iteration aborts and the exception propagates. The callback is registered as a *global root* while the loop runs, guaranteeing it stays reachable for the GC. |
| `count_frames` | A tiny helper used by the convenience function in the `.mli`. It is not exposed to OCaml directly; the `.mli` implements it via `external` (see below). |
| `caml_pcapng_init` | Simple init function that registers the exception name. It is called automatically by the OCaml runtime when the library is loaded. |

### 2.2. The C++ side (hypothetical) – what we assume from *libpcapng*

```cpp
// libpcapng.hpp  (illustrative – replace with the real header)

namespace pcapng {

struct Frame {
    uint32_t timestamp_sec;   // seconds since epoch
    uint32_t timestamp_usec;  // microseconds part
    uint32_t caplen;           // captured length
    uint32_t origlen;          // original length on the wire
    std::vector<uint8_t> payload; // size == caplen
};

class Reader {
public:
    explicit Reader(const std::string &filename);   // throws on error
    // Returns std::nullopt when EOF is reached.
    std::optional<Frame> next_frame();
    // Destructor releases the file handle.
    ~Reader();
};
}
```

You **must replace** the `#include "libpcapng.hpp"` line with the actual header(s) that ship with your library, and adapt the field names (`timestamp_sec`, `timestamp_usec`, …) accordingly.

---

## 3. Building the binding

Assuming the two source files are placed in a directory `src/`, the typical OCaml build steps are:

```sh
# 1. Compile the C++ stub as a PIC object (must be compiled with a C++ compiler)
g++ -std=c++17 -I$(ocamlc -where) -I/path/to/libpcapng/include \
    -fPIC -c src/pcapng_stubs.c -o src/pcapng_stubs.o

# 2. Build a shared library that OCaml can load
g++ -shared -o src/libpcapng_stubs.so src/pcapng_stubs.o \
    -L/path/to/libpcapng/lib -lpcapng

# 3. Compile the OCaml interface & implementation (the implementation is tiny)
ocamlc -c src/pcapng.mli
ocamlc -c src/pcapng.ml   # contains only the external declarations

# 4. Archive the objects into a .cma/.cmxa (optional)
ocamlc -a -o pcapng.cma src/pcapng.cmo -dllib -lpcapng_stubs
ocamlopt -a -o pcapng.cmxa src/pcapng.cmx -cclib -lpcapng_stubs

# 5. Link a test program
ocamlc -I src -o test.exe pcapng.cma test.ml
```

*Replace `/path/to/libpcapng/...` with the real locations on your system.*

If you are using `dune`, the stanza is even simpler:

```dune
(library
 (name pcapng)
 (foreign_stubs
   (language c)
   (flags (:standard -std=c++17))
   (names pcapng_stubs))
 (libraries pcapng) ; the external C++ library
 (c_names pcapng_stubs.c))
```

`dune` will automatically compile the stub as C++ and link the resulting shared object.

