## 4. Minimal OCaml implementation (`pcapng.ml`)

```ocaml
(*--------------------------------------------------------------------
   pcapng.ml – thin wrappers around the C primitives
   --------------------------------------------------------------------*)

type frame = {
  ts_sec   : int;
  ts_usec  : int;
  caplen   : int;
  origlen  : int;
  data     : bytes;
}

type t

exception Error of string

(* Register the exception name for the C stub (done at load time) *)
let () = Callback.register_exception "Pcapng.Error" (Error "")

external open_file : string -> t = "caml_pcapng_open_file"
external iter      : t -> (frame -> unit) -> unit = "caml_pcapng_iter"
external next      : t -> frame option = "caml_pcapng_next"

(* Convenience helper implemented in OCaml using the primitives above *)
let count_frames filename =
  let rdr = open_file filename in
  let rec loop acc =
    match next rdr with
    | None -> acc
    | Some _ -> loop (acc + 1)
  in
  loop 0
```

